function make_palindrome(string) {
    if (string.length <= 1) return string;

    // Find the longest palindromic suffix
    // A suffix starting at index i is a palindrome if string[i..end] is a palindrome
    let start = -1;
    for (let i = 0; i < string.length; i++) {
        // Check if string[i..length-1] is a palindrome
        let left = i;
        let right = string.length - 1;
        let isPalindrome = true;
        while (left < right) {
            if (string[left] !== string[right]) {
                isPalindrome = false;
                break;
            }
            left++;
            right--;
        }
        if (isPalindrome) {
            start = i;
            break; // First one found is the longest palindromic suffix
        }
    }

    if (start === 0) return string; // The whole string is already a palindrome

    // The prefix before the palindromic suffix is string[0..start-1]
    let prefix = string.substring(0, start);
    let reversedPrefix = prefix.split('').reverse().join('');

    return string + reversedPrefix;
}
