function factorize(n) {
    const factors = [];

    // Handle edge cases
    if (n <= 1) {
        return factors;
    }

    // Divide by 2 until no longer divisible
    while (n % 2 === 0) {
        factors.push(2);
        n = n / 2;
    }

    // Now n must be odd, so we can skip even numbers
    for (let i = 3; i <= Math.sqrt(n); i += 2) {
        while (n % i === 0) {
            factors.push(i);
            n = n / i;
        }
    }

    // If n is still greater than 1, then it's a prime factor
    if (n > 1) {
        factors.push(n);
    }

    return factors;
}
