    // Divide out all factors of 2
    while (n % 2 === 0) {
        largest = 2;
        n = n / 2;
    }

    // Now n must be odd. Check for odd factors starting from 3.
    for (let i = 3; i <= Math.sqrt(n); i += 2) {
        while (n % i === 0) {
            largest = i;
            n = n / i;
        }
