function starts_one_ends(n) {
    if (n === 1) {
        // For 1-digit numbers, the number is just 1 (starts and ends with 1)
        return 1;
    }

    // Count of n-digit numbers that start with 1:
    // First digit is 1, remaining n-1 digits can be anything (0-9)
    // So there are 10^(n-1) such numbers.
    const startsWithOne = Math.pow(10, n - 1);

    // Count of n-digit numbers that end with 1:
    // Last digit is 1, first digit can be 1-9 (can't be 0 for n-digit number), 
    // middle n-2 digits can be anything (0-9)
    // So there are 9 * 10^(n-2) such numbers.
    const endsWithOne = 9 * Math.pow(10, n - 2);

    // Count of n-digit numbers that both start and end with 1:
    // First digit is 1, last digit is 1, middle n-2 digits can be anything (0-9)
    // So there are 10^(n-2) such numbers.
    const startsAndEndsWithOne = Math.pow(10, n - 2);

    // Use inclusion-exclusion principle:
    // |A ∪ B| = |A| + |B| - |A ∩ B|
    return startsWithOne + endsWithOne - startsAndEndsWithOne;
}
