            // Let's check binary representations for negative numbers.
            // In JavaScript, bitwise operations work on 32-bit signed integers.
            // -1 is represented as all 1s in two's complement (32 ones).
            // -2 is ...111110 (31 ones)
            // -3 is ...111101 (31 ones)
            // -4 is ...111100 (30 ones)
            // -5 is ...111011 (30 ones)
            // -6 is ...111010 (30 ones)

            // For negative numbers, we can use the unsigned right shift to get the 32-bit representation
            // and then count bits. Or we can just use n >>> 0 to convert to unsigned 32-bit integer.
            let num = n >>> 0; // Convert to unsigned 32-bit integer
            let count = 0;
            while (num) {
                count += num & 1;
                num >>= 1;
            }
            return count;
        };

        const onesA = countOnes(a);
        const onesB = countOnes(b);

        if (onesA !== onesB) {
            return onesA - onesB;
        } else {
            return a - b;
        }
    });
}
