function get_closest_vowel(word) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U']);

    function isVowel(char) {
        return vowels.has(char);
    }

    function isConsonant(char) {
        return /[a-zA-Z]/.test(char) && !isVowel(char);
    }

    // We need to find the closest vowel from the right side that stands between two consonants.
    // "Closest from the right" means we should search from the end of the string towards the beginning,
    // and return the first one we find that meets the condition.

    // The vowel must be between two consonants, meaning:
    // - The character before it is a consonant
    // - The character after it is a consonant
    // - Vowels at the beginning or end don't count (which is naturally handled since they won't have both neighbors)

    for (let i = word.length - 1; i >= 0; i--) {
        if (isVowel(word[i])) {
            // Check if it's between two consonants
            if (i > 0 && i < word.length - 1) {
                if (isConsonant(word[i - 1]) && isConsonant(word[i + 1])) {
                    return word[i];
                }
            }
        }
    }

    return "";
}
