function get_odd_collatz(n) {
    const odds = new Set();
    let current = n;

    while (current !== 1) {
        if (current % 2 !== 0) {
            odds.add(current);
        }
        if (current % 2 === 0) {
            current = current / 2;
        } else {
            current = 3 * current + 1;
        }
    }

    // Add 1 since the sequence always ends at 1
    odds.add(1);

    return Array.from(odds).sort((a, b) => a - b);
}
