function minPath(grid, k) {
    const N = grid.length;

    // Find all starting positions and sort them by value to try smallest first
    let starts = [];
    for (let i = 0; i < N; i++) {
        for (let j = 0; j < N; j++) {
            starts.push({r: i, c: j, val: grid[i][j]});
        }
    }
    // Sort by value ascending so we can try smallest starting values first
    starts.sort((a, b) => a.val - b.val);

    // For each starting cell, do DFS/BFS to find the lexicographically smallest path of length k
    // Since we want the overall minimum, we can use a priority queue approach or just generate all paths from the best start

    // Actually, since N is small (implied by typical competitive programming constraints for this type), 
    // and k might be large, we need an efficient approach.

    // Key insight: We want the lexicographically smallest sequence of length k.
    // This is equivalent to finding a path that minimizes the sequence in lex order.

    // Approach: Use DFS with pruning or iterative deepening. But since k can be large, we need to be smart.

    // Better approach: At each step, among all current paths of length L, extend them to length L+1 by choosing 
    // the smallest possible next value. This is like a BFS where we keep only the "best" paths at each level.

    // However, multiple paths can lead to different positions with same sequence prefix. We need to track (position, path).

    // Since the answer is unique and we want lex smallest, we can do:
    // Level 0: all cells as starting points, grouped by their value. Pick the smallest value cell(s) as candidates.
    // But wait - multiple cells might have same value? No, values are unique [1, N*N].

    // So at level 0, pick the cell with minimum value globally? Not necessarily - because the path of length k 
    // starting from min value might not be lex smallest if it forces large values later.

    // Actually for lex comparison, we compare element by element. So first element matters most.
    // Among all paths of length k, the one with smallest first element is preferred. If tie, smallest second, etc.

    // So: Find all cells. The best path must start with the globally minimum value? 
    // Yes! Because if a path starts with value v1 and another with v2 where v1 < v2, then the first path is lex smaller regardless of rest.

    // Wait, but we need paths of exactly length k. So we should:
    // 1. Find the cell with minimum value - call it startCell. There's only one such cell since all values unique.
    // 2. From startCell, find the lex smallest path of length k.

    // Hmm, but what if starting from the global min doesn't allow a path of length k? 
    // Actually we can revisit cells, so any cell can be part of a path of any length >= 1.

    // So algorithm:
    // Step 1: Find the cell with minimum value in entire grid. This must be the start of our optimal path.
    // Step 2: From that cell, greedily build the path: at each step, among all neighbors (including staying? no, must move to neighbor), 
    //         pick the one with smallest value. But wait - we need to consider future steps too for lex order.

    // Actually, greedy works for lex smallest path! At each position, to minimize the next element in the sequence, 
    // we should pick the neighbor with the smallest value. This is because lex comparison is determined by the first differing element.

    // Let me verify: Suppose at step i, we're at cell C. We have two choices: go to A (value 2) or B (value 3).
    // Path through A: [..., val(C), 2, ...]
    // Path through B: [..., val(C), 3, ...]
    // The first path is lex smaller regardless of what comes after. So greedy choice is correct!

    // Therefore:
    // 1. Find global minimum cell - this is our start.
    // 2. For k-1 more steps, at each step move to the neighbor with the smallest value.

    let minVal = Infinity;
    let startR = -1, startC = -1;
    for (let i = 0; i < N; i++) {
        for (let j = 0; j < N; j++) {
            if (grid[i][j] < minVal) {
                minVal = grid[i][j];
                startR = i;
                startC = j;
            }
        }
    }

    let path = [grid[startR][startC]];
    let curR = startR, curC = startC;

    const dirs = [[-1,0],[1,0],[0,-1],[0,1]];

    for (let step = 1; step < k; step++) {
        let bestVal = Infinity;
        let nextR = -1, nextC = -1;

        for (let [dr, dc] of dirs) {
            let nr = curR + dr;
            let nc = curC + dc;
            if (nr >= 0 && nr < N && nc >= 0 && nc < N) {
                if (grid[nr][nc] < bestVal) {
                    bestVal = grid[nr][nc];
                    nextR = nr;
                    nextC = nc;
                }
            }
        }

        path.push(bestVal);
        curR = nextR;
        curC = nextC;
    }

    return path;
}

