function tri(n) {
    if (n < 0) return [];

    // We need to compute tri(0) through tri(n)
    // Let's define the sequence values in an array

    // Base cases from problem:
    // tri(1) = 3
    // For even n: tri(n) = 1 + n / 2
    // For odd n (n > 1): tri(n) = tri(n-1) + tri(n-2) + tri(n+1)

    // Wait, the recurrence for odd n references tri(n+1), which is a future value.
    // Let's analyze: if n is odd, tri(n) = tri(n-1) + tri(n-2) + tri(n+1)
    // But tri(n+1) when n is odd means n+1 is even, so tri(n+1) = 1 + (n+1)/2

    // So for odd n: tri(n) = tri(n-1) + tri(n-2) + (1 + (n+1)/2)

    // We also need tri(0). Looking at the example: tri(3) returns [1, 3, 2, 8]
    // So tri(0) = 1, tri(1) = 3, tri(2) = 2, tri(3) = 8

    // Let's verify tri(0): if we apply the even formula to n=0: tri(0) = 1 + 0/2 = 1. That matches!

    const result = new Array(n + 1);

    for (let i = 0; i <= n; i++) {
        if (i === 0) {
            result[i] = 1; // tri(0) = 1 + 0/2 = 1
        } else if (i % 2 === 0) {
            // Even case: tri(n) = 1 + n / 2
            result[i] = 1 + i / 2;
        } else {
            // Odd case: tri(n) = tri(n-1) + tri(n-2) + tri(n+1)
            // tri(n+1) is even, so tri(n+1) = 1 + (n+1)/2
            const triNPlus1 = 1 + (i + 1) / 2;
            result[i] = result[i - 1] + result[i - 2] + triNPlus1;
        }
    }

    return result;
}
