function check_if_last_char_is_a_letter(txt) {
    if (!txt || txt.length === 0) {
        return false;
    }

    const lastChar = txt[txt.length - 1];

    // Check if the last character is an alphabetical letter
    if (!/[a-zA-Z]/.test(lastChar)) {
        return false;
    }

    // Check if the last character is not part of a word.
    // A "word" is a group of characters separated by space.
    // If the last character is a letter, it's part of a word unless it's isolated.
    // Looking at the examples:
    // "apple pie" -> last char 'e' is part of "pie", so false.
    // "apple pi e" -> last char 'e' is its own word (separated by space), so true.
    // "apple pi e " -> last char is space, not a letter, so false.

    // So we need to check if the last character forms a word by itself.
    // This means the character before it (if any) must be a space, and there should be no more characters after it (which is true since it's the last char).
    // Also, the last character itself must not be preceded by another letter/digit/etc that would make it part of a larger word.

    // Let's trim trailing spaces first? No, the example "apple pi e " returns false because the last char is space.
    // So we already handled non-letter last chars.

    // Now, for the last char to be a letter and NOT part of a word:
    // It must be that this letter is isolated by spaces.
    // Since it's the last character, we just need to check if the previous character is a space (or if it's the first character).

    const prevChar = txt.length > 1 ? txt[txt.length - 2] : null;

    // If there's no previous character, then this single letter is its own word.
    if (prevChar === null) {
        return true;
    }

    // If the previous character is a space, then this letter is its own word.
    if (prevChar === ' ') {
        return true;
    }

    // Otherwise, it's part of a larger word.
    return false;
}
